 249→  const [colorFilterValue, setColorFilterValue] = useState('all');
 250→  const [selectedIndex, setSelectedIndex] = useState(0);
 251→  const [actionsOpen, setActionsOpen] = useState(false);
 252→  const [quickLookOpen, setQuickLookOpen] = useState(false);
 253→  const { toasts, show: showToast, hide: hideToast } = useToast();
 254→  const { items: hudItems, show: showHUD } = useHUD();
 255→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
 256→  const nav = useNavigationStack<NavViewData>('Raycast');
 257→  const { push } = nav;
 258→  const { favoriteIds, isFavorite, toggleFavorite, moveFavorite } =
 259→    useFavorites();
