 271→        ],
 272→      },
 273→      {
 274→        title: 'Types',
 275→        options: [
 276→          {
 277→            label: 'Commands',
 278→            value: 'commands',
 279→          },
 280→          {
 281→            label: 'Applications',
 282→            value: 'applications',
 283→          },
 284→        ],
 285→      },
 286→    ],
 287→    [],
 288→  );
 289→
 290→  const colorFilterSections: SearchDropdownSection[] = useMemo(
 291→    () => [
 292→      {
 293→        options: [
 294→          {
 295→            label: 'All Colors',
 296→            value: 'all',
 297→          },
 298→        ],
 299→      },
 300→      {
 301→        title: 'Category',
 302→        options: [
 303→          {
 304→            label: 'Warm',
 305→            value: 'warm',
 306→          },
 307→          {
 308→            label: 'Cool',
 309→            value: 'cool',
 310→          },
 311→          {
 312→            label: 'Neutral',
 313→            value: 'neutral',
 314→          },
 315→        ],
 316→      },
 317→    ],
 318→    [],
