 320→
 321→  useEffect(() => {
 322→    if (nav.stackDepth === 0) {
 323→      setQuery('');
 324→      setFilterValue('all');
 325→      setColorFilterValue('all');
 326→      setSelectedIndex(0);
 327→      setActionsOpen(false);
 328→      setQuickLookOpen(false);
