 332→  const filtered = useMemo(() => {
 333→    let sections = MOCK_SECTIONS;
 334→    if (filterValue === 'commands') {
 335→      sections = sections.filter(
 336→        s => s.title === 'Suggestions' || s.title === 'Commands',
 337→      );
 338→    } else if (filterValue === 'applications') {
 339→      sections = sections.filter(s => s.title === 'Applications');
 340→    }
 341→    const result = filterSections(sections, query);
 342→
 343→    const allFlatItems = sections.flatMap(s => s.items);
 344→    const favoriteItems = favoriteIds
 345→      .map(id => allFlatItems.find(item => item.id === id))
 346→      .filter((item): item is ListItemData => !!item);
 347→
 348→    if (query) {
 349→      const lower = query.toLowerCase();
 350→      const filteredFavs = favoriteItems.filter(
 351→        item =>
 352→          item.title.toLowerCase().includes(lower) ||
 353→          item.subtitle?.toLowerCase().includes(lower),
 354→      );
 355→      if (filteredFavs.length > 0) {
 356→        const favIds = new Set(filteredFavs.map(f => f.id));
 357→        const dedupedSections = result
 358→          .map(s => ({
 359→            ...s,
 360→            items: s.items.filter(item => !favIds.has(item.id)),
