 374→    if (favoriteItems.length > 0) {
 375→      const favIds = new Set(favoriteIds);
 376→      const dedupedSections = result
 377→        .map(s => ({
 378→          ...s,
 379→          items: s.items.filter(item => !favIds.has(item.id)),
 380→        }))
 381→        .filter(s => s.items.length > 0);
 382→      return [
 383→        {
 384→          title: 'Favorites',
 385→          items: favoriteItems,
 386→        },
